// routes.js — re-exports bundled route data and world name map.
// routes-data.js is generated by: node bundle-routes.mjs

export { routes } from '../data/routes-data.js';

export const WORLD_NAMES = {
  watopia:         'Watopia',
  london:          'London',
  'new-york':      'New York',
  innsbruck:       'Innsbruck',
  richmond:        'Richmond',
  bologna:         'Bologna',
  yorkshire:       'Yorkshire',
  'crit-city':     'Crit City',
  'makuri-islands':'Makuri Islands',
  france:          'France',
  paris:           'Paris',
  scotland:        'Scotland',
};

// todaysWorlds accepts the user's chosen guest worlds (stored in localStorage via app.js).
// Watopia is always included. Pass an empty array to get Watopia only.
export function todaysWorlds(guestWorlds = []) {
  const available = new Set(['watopia']);
  for (const w of guestWorlds) available.add(w);
  return available;
}

export function filterToAvailableWorlds(routes, guestWorlds = []) {
  const available = todaysWorlds(guestWorlds);
  return routes.filter(r => available.has(r.world));
}

export function worldName(slug) {
  return WORLD_NAMES[slug] ?? slug;
}
